@import url('https://fonts.googleapis.com/css2?family=Poppins:wght@400;500;600;700&display=swap');

:root {
	--font-primary: 'Poppins', sans-serif;

	--color-text-dark: #2D3748; 
	--color-text-gray: #718096;

	--color-bg: #ffffff;
	--color-border: #E2E8F0;

	--color-primary: #82DB34; 
	--color-primary-hover: #75C62F; 
	--color-ai-blue: #2e6fc1;
	--color-ai-blue-hover: #255a9c;
    --color-accordion-open: #f0f7ff; /* Bleu très léger pour l'accordéon ouvert */

	--radius-main: 16px;
	--radius-sm: 8px;
	--radius-pill: 50px;
}

body, html {
	margin: 0;
	padding: 0;
	font-family: var(--font-primary);
	color: var(--color-text-dark);
	background-color: var(--color-bg); /* Fond 100% blanc */
}

.dashboard-container {
	display: flex;
	flex-direction: column;
	max-width: 1200px;
	margin: 0 auto;
	padding: 0; /* Suppression du padding global pour coller aux bords si besoin */
}

/* =========================================
   Section IA (Premium stylisé)
========================================= */
.block-ai-wrapper {
    padding: 24px;
}

.block-ai {
	position: relative;
	background-color: var(--color-ai-blue);
	color: white;
	display: flex;
	flex-direction: row;
	align-items: center;
	justify-content: space-between;
	padding: 40px 48px;
	border-radius: var(--radius-main);
	gap: 32px;
	overflow: hidden; 
	box-shadow: 0 10px 25px -5px rgba(46, 111, 193, 0.3); 
}

.block-ai::before {
	content: '';
	position: absolute;
	top: -50%;
	right: -5%;
	width: 300px;
	height: 300px;
	background: radial-gradient(circle, #4a8deb 0%, transparent 70%);
	opacity: 0.9;
	pointer-events: none;
}

.block-ai::after {
	content: '';
	position: absolute;
	inset: 0;
	background-image: 
		radial-gradient(circle, rgba(255, 255, 255, 0.08) 15%, transparent 15%),
		repeating-linear-gradient(-45deg, rgba(255, 255, 255, 0.03) 0, rgba(255, 255, 255, 0.03) 1px, transparent 1px, transparent 15px);
	pointer-events: none;
	opacity: 0.8;
}

.ai-text, .btn-ai {
	position: relative;
	z-index: 2;
}

.ai-text h2 {
	margin: 0 0 12px 0;
	font-size: 1.6rem; 
	font-weight: 700;
}

.ai-text p {
	margin: 0;
	font-size: 1.05rem; 
	opacity: 0.95;
	line-height: 1.5;
	max-width: 480px;
}

.btn-ai {
	background-color: #ffffff;
	color: var(--color-ai-blue);
	border: none;
	padding: 14px 28px;
	border-radius: var(--radius-pill);
	font-family: var(--font-primary);
	font-weight: 700;
	font-size: 1.05rem;
	cursor: pointer;
	transition: all 0.3s ease;
	display: flex;
	align-items: center;
	gap: 10px;
	white-space: nowrap;
	box-shadow: 0 4px 15px rgba(0, 0, 0, 0.1);
}

.btn-ai:hover {
	transform: translateY(-3px) scale(1.02);
	box-shadow: 0 8px 25px rgba(0, 0, 0, 0.2);
	color: var(--color-ai-blue-hover);
}

@keyframes sparklePulse {
	0%, 100% { transform: scale(1); opacity: 1; }
	50% { transform: scale(1.15); opacity: 0.7; }
}
.btn-ai svg {
	animation: sparklePulse 2s infinite ease-in-out;
}

/* =========================================
   Sections séparées par des bordures
========================================= */
.content-block {
	padding: 40px 24px;
	border-bottom: 1px solid var(--color-border);
}

.content-block:last-child {
    border-bottom: none;
}

.section-header {
	margin-bottom: 24px;
}

.section-title {
	font-size: 1.4rem;
	font-weight: 700;
	margin: 0 0 4px 0;
	color: var(--color-text-dark);
}

.section-subtitle {
	font-size: 0.95rem;
	color: var(--color-text-gray);
	margin: 0;
}

/* =========================================
   Layout Verticales en colonnes
========================================= */
.verticales-layout {
	display: grid;
	grid-template-columns: 1fr 1fr; 
	gap: 32px; 
	margin-top: 16px;
}

.verticales-col-right {
	display: flex;
	flex-direction: column;
	gap: 32px; 
}

.universe-title {
	font-size: 1rem;
	font-weight: 700;
	color: var(--color-text-dark);
	margin: 0 0 16px 0;
	text-transform: uppercase;
	letter-spacing: 0.05em;
	padding-left: 4px;
}

/* =========================================
   Accordéon avec fond bleu ciblé
========================================= */
.accordion-list {
	display: flex;
	flex-direction: column;
	gap: 12px;
}

.accordion-item {
	border: 1px solid var(--color-border);
	border-radius: var(--radius-sm);
	overflow: hidden;
    transition: all 0.2s ease;
}

/* État fermé */
.accordion-header {
	width: 100%;
	display: flex;
	align-items: center;
	justify-content: space-between;
	padding: 16px 20px;
	background: var(--color-bg);
	border: none;
	cursor: pointer;
	font-family: var(--font-primary);
	font-size: 1rem;
	font-weight: 600;
	color: var(--color-text-dark);
	transition: background 0.2s;
}

.accordion-header:hover {
	background-color: #f8fafc;
}

/* État Ouvert (Bleu léger) */
.accordion-item.is-open {
    border-color: #93c5fd; /* Bordure plus bleutée */
}

.accordion-item.is-open .accordion-header {
	background-color: var(--color-accordion-open);
    border-bottom: 1px solid #bfdbfe;
}

.accordion-body {
	padding: 20px;
	background-color: var(--color-accordion-open);
	font-size: 0.95rem;
	color: var(--color-text-dark);
	display: flex;
	flex-direction: column;
	gap: 16px;
}

.accordion-header-left {
	display: flex;
	align-items: center;
	gap: 12px;
}

.accordion-icon {
	font-size: 1.4rem;
}

.accordion-chevron {
	color: var(--color-text-gray);
	transition: transform 0.3s ease;
}

.accordion-item.is-open .accordion-chevron {
	transform: rotate(180deg);
    color: var(--color-ai-blue);
}

/* =========================================
   Boutons Documents & Badges
========================================= */
.document-list {
	display: flex;
	flex-direction: column;
	gap: 12px;
}

.btn-document {
	display: flex;
	align-items: center;
	justify-content: space-between;
	padding: 12px 16px;
	background-color: #ffffff; /* Fond blanc au lieu de gris pour ressortir sur le bleu */
	border: 1px solid var(--color-border);
	border-radius: var(--radius-sm);
	cursor: pointer;
	font-family: var(--font-primary);
	font-size: 0.95rem;
	font-weight: 500;
	color: var(--color-text-dark);
	transition: all 0.2s;
	text-decoration: none;
	width: 100%;
    box-shadow: 0 1px 2px rgba(0,0,0,0.02);
}

.btn-document:hover {
	border-color: var(--color-ai-blue);
	background-color: #f8fafc;
    transform: translateX(2px);
}

.btn-doc-left {
	display: flex;
	align-items: center;
	gap: 12px;
    text-align: left;
}

.btn-doc-right {
	display: flex;
	align-items: center;
	gap: 12px;
}

/* Badges dynamiques */
.badge {
	padding: 4px 8px;
	border-radius: 4px;
	font-size: 0.75rem;
	font-weight: 700;
	text-transform: uppercase;
	letter-spacing: 0.05em;
    white-space: nowrap;
}

.badge-pdf { background-color: #fee2e2; color: #dc2626; }
.badge-video { background-color: #e0e7ff; color: #4f46e5; }
.badge-word { background-color: #dbeafe; color: #2563eb; }
.badge-presentation { background-color: #fef3c7; color: #d97706; } /* NOUVEAU */
.badge-infographie { background-color: #fce7f3; color: #db2777; } /* NOUVEAU */
.badge-lien { background-color: #f3f4f6; color: #4b5563; }

/* Responsive Mobile */
@media screen and (max-width: 900px) {
	.verticales-layout {
		grid-template-columns: 1fr; 
		gap: 32px;
	}
}

@media screen and (max-width: 600px) {
	.block-ai {
		flex-direction: column;
		text-align: center;
		padding: 32px 24px;
	}
	.btn-document {
		flex-direction: column;
		align-items: flex-start;
		gap: 12px;
	}
	.btn-doc-right {
		width: 100%;
		justify-content: flex-end;
	}
}

